export interface EmailRecord {
  id: string;
  date: string; // ISO String YYYY-MM-DD
  subject: string;
  sender: string;
}

export interface DateRange {
  startDate: string;
  endDate: string;
}

export interface AnalysisSummary {
  totalCount: number;
  dailyAverage: number;
  busiestDay: string;
  aiInsights: string;
}

export enum LoadingState {
  IDLE = 'IDLE',
  PARSING = 'PARSING',
  ANALYZING = 'ANALYZING',
  ERROR = 'ERROR',
  SUCCESS = 'SUCCESS'
}

import { GoogleGenAI, Type } from "@google/genai";
import { EmailRecord } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

export const parseRawEmailData = async (rawData: string): Promise<EmailRecord[]> => {
  const ai = getAiClient();

  // We use a looser model for reasoning/parsing unstructured text
  const model = "gemini-3-flash-preview"; 

  const prompt = `
    You are a data parser. I have a raw text containing email information. 
    Please extract the Date, Sender, and Subject for each email found.

    If the year is missing, assume the current year is 2024.
    Format dates as ISO 8601 strings (YYYY-MM-DD).
    Return the result as a JSON array of objects.

    Raw Data:
    ${rawData}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING, description: "YYYY-MM-DD format" },
              sender: { type: Type.STRING },
              subject: { type: Type.STRING }
            },
            required: ["date", "sender", "subject"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);
    return parsed.map((item: any, index: number) => ({
      ...item,
      id: `email-${Date.now()}-${index}`
    }));
  } catch (error) {
    console.error("Failed to parse email data via Gemini", error);
    throw new Error("Could not interpret the provided data. Please ensure it contains readable email info.");
  }
};

export const generateAnalysisSummary = async (emails: EmailRecord[], startDate: string, endDate: string): Promise<string> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview";

  const emailContext = JSON.stringify(emails.slice(0, 50)); // Limit context if too large, usually okay for summaries

  const prompt = `
    Analyze this list of emails received between ${startDate} and ${endDate}.
    Provide a brief, professional summary of the volume patterns. 
    Mention which days seem busiest or if there are any notable trends in senders or subjects.
    Keep it under 3 sentences.

    Email Data Sample:
    ${emailContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error("Analysis failed", error);
    return "Could not generate AI insights at this time.";
  }
};

