import React from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { EmailRecord, AnalysisSummary, LoadingState } from '../types';
import { Mail, TrendingUp, CalendarCheck, Lightbulb } from 'lucide-react';

interface DashboardProps {
  filteredEmails: EmailRecord[];
  summary: AnalysisSummary | null;
  loadingState: LoadingState;
}

export const Dashboard: React.FC<DashboardProps> = ({ filteredEmails, summary, loadingState }) => {
  if (loadingState === LoadingState.IDLE || (loadingState === LoadingState.PARSING && !filteredEmails.length)) {
    return (
      <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
        <Mail className="w-12 h-12 mb-3 opacity-20" />
        <p>Enter data and select a date range to view analysis</p>
      </div>
    );
  }

  // Aggregate data for chart
  const chartDataMap = new Map<string, number>();

  // Sort emails by date first to ensure chart order
  const sortedEmails = [...filteredEmails].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  sortedEmails.forEach(email => {
    const date = email.date;
    chartDataMap.set(date, (chartDataMap.get(date) || 0) + 1);
  });

  const chartData = Array.from(chartDataMap.entries()).map(([date, count]) => ({
    date,
    count
  }));

  const isAnalyzing = loadingState === LoadingState.ANALYZING;

  return (
    <div className="space-y-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-50 rounded-lg">
              <Mail className="w-5 h-5 text-blue-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Total Messages</h3>
          </div>
          <p className="text-2xl font-bold text-slate-800">{filteredEmails.length}</p>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-emerald-50 rounded-lg">
              <TrendingUp className="w-5 h-5 text-emerald-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Daily Average</h3>
          </div>
          <p className="text-2xl font-bold text-slate-800">
            {summary ? summary.dailyAverage.toFixed(1) : '-'}
          </p>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-purple-50 rounded-lg">
              <CalendarCheck className="w-5 h-5 text-purple-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Busiest Day</h3>
          </div>
          <p className="text-lg font-bold text-slate-800 truncate">
             {summary ? summary.busiestDay : '-'}
          </p>
        </div>
      </div>

      {/* Chart */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-semibold text-slate-800 mb-6">Message Volume Over Time</h3>
        <div className="h-[300px] w-full">
          {chartData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 5, right: 30, left: 0, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis 
                  dataKey="date" 
                  tick={{ fontSize: 12, fill: '#64748b' }} 
                  axisLine={false} 
                  tickLine={false} 
                  minTickGap={30}
                  tickFormatter={(value) => {
                    const d = new Date(value);
                    return `${d.getMonth() + 1}/${d.getDate()}`;
                  }}
                />
                <YAxis 
                   tick={{ fontSize: 12, fill: '#64748b' }} 
                   axisLine={false} 
                   tickLine={false}
                   allowDecimals={false}
                />
                <Tooltip 
                  cursor={{ fill: '#f1f5f9' }}
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                   {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill="#6366f1" />
                    ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="h-full flex items-center justify-center text-slate-400 text-sm">
              No data points in this range
            </div>
          )}
        </div>
      </div>

      {/* AI Summary */}
      <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100">
        <div className="flex items-start gap-3">
          <Lightbulb className="w-6 h-6 text-indigo-600 flex-shrink-0 mt-1" />
          <div className="flex-1">
            <h3 className="text-indigo-900 font-semibold mb-1">AI Insights</h3>
            {isAnalyzing ? (
               <div className="h-4 bg-indigo-200/50 rounded animate-pulse w-3/4 mt-2"></div>
            ) : (
              <p className="text-indigo-800 text-sm leading-relaxed">
                {summary?.aiInsights || "Generate data to see AI-powered insights regarding your email traffic."}
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { InputSection } from './components/InputSection';
import { DateFilter } from './components/DateFilter';
import { Dashboard } from './components/Dashboard';
import { parseRawEmailData, generateAnalysisSummary } from './services/geminiService';
import { EmailRecord, DateRange, AnalysisSummary, LoadingState } from './types';
import { LayoutDashboard } from 'lucide-react';

const App: React.FC = () => {
  const [emails, setEmails] = useState<EmailRecord[]>([]);
  const [dateRange, setDateRange] = useState<DateRange>({
    startDate: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0]
  });
  const [summary, setSummary] = useState<AnalysisSummary | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);

  const handleParse = async (rawData: string) => {
    setLoadingState(LoadingState.PARSING);
    try {
      const parsedEmails = await parseRawEmailData(rawData);
      setEmails(parsedEmails);

      // Auto-adjust date range to fit the data if it's outside the current range
      if (parsedEmails.length > 0) {
        const dates = parsedEmails.map(e => new Date(e.date).getTime());
        const minDate = new Date(Math.min(...dates)).toISOString().split('T')[0];
        const maxDate = new Date(Math.max(...dates)).toISOString().split('T')[0];

        // Only update if current range doesn't cover data or is default
        setDateRange(prev => ({
           startDate: minDate < prev.startDate ? minDate : prev.startDate,
           endDate: maxDate > prev.endDate ? maxDate : prev.endDate
        }));
      }

      setLoadingState(LoadingState.SUCCESS);
    } catch (error) {
      setLoadingState(LoadingState.ERROR);
    }
  };

  // Filter emails based on range
  const filteredEmails = useMemo(() => {
    const start = new Date(dateRange.startDate).getTime();
    // End date needs to include the full day, so we set it to end of day conceptually, 
    // but simple string comparison works if we are consistent. 
    // Let's use timestamp comparison for safety.
    const end = new Date(dateRange.endDate).getTime();

    return emails.filter(email => {
      const emailDate = new Date(email.date).getTime();
      return emailDate >= start && emailDate <= end;
    });
  }, [emails, dateRange]);

  // Run analysis when filtered emails change
  useEffect(() => {
    const runAnalysis = async () => {
      if (filteredEmails.length === 0) {
        setSummary(null);
        return;
      }

      setLoadingState(LoadingState.ANALYZING);

      // Basic stats calculation (Synchronous)
      const dayCounts = new Map<string, number>();
      filteredEmails.forEach(e => {
         dayCounts.set(e.date, (dayCounts.get(e.date) || 0) + 1);
      });

      const uniqueDays = dayCounts.size || 1; // Avoid divide by zero
      const dailyAvg = filteredEmails.length / uniqueDays;

      let busiestDay = '';
      let maxCount = 0;
      dayCounts.forEach((count, day) => {
        if (count > maxCount) {
          maxCount = count;
          busiestDay = day;
        }
      });

      // AI Summary (Asynchronous)
      try {
        const aiText = await generateAnalysisSummary(filteredEmails, dateRange.startDate, dateRange.endDate);

        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: aiText
        });
        setLoadingState(LoadingState.SUCCESS);
      } catch (err) {
        // Even if AI fails, we show basic stats
        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: "AI analysis unavailable."
        });
        setLoadingState(LoadingState.SUCCESS);
      }
    };

    // Debounce analysis to avoid too many API calls while dragging dates (if we had a slider)
    // For date picker inputs, simple timeout is fine.
    const timeoutId = setTimeout(() => {
        runAnalysis();
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [filteredEmails, dateRange]); // Dependencies

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-12">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
               <LayoutDashboard className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-700 to-indigo-500 bg-clip-text text-transparent">
              MailPulse Analytics
            </h1>
          </div>
          <div className="text-sm text-slate-500">
             Powered by Gemini 3
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="lg:col-span-4 space-y-6">
            <InputSection onParse={handleParse} loadingState={loadingState} />
            <DateFilter dateRange={dateRange} onDateChange={setDateRange} />
          </div>

          {/* Right Column: Dashboard */}
          <div className="lg:col-span-8">
             <Dashboard 
                filteredEmails={filteredEmails} 
                summary={summary} 
                loadingState={loadingState} 
             />
          </div>

        </div>

      </main>
    </div>
  );
};

export default App;

