import { GoogleGenAI, Type } from "@google/genai";
import { EmailRecord, Account, DateRange } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

// Since we cannot actually access IMAP servers from a browser client without a backend proxy,
// we use Gemini to simulate the "fetching" process and generate realistic data based on the accounts provided.
export const fetchSimulatedEmails = async (accounts: Account[], dateRange: DateRange): Promise<EmailRecord[]> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview"; 

  const accountsList = accounts.map(a => a.email).join(', ');

  const prompt = `
    Act as a mail server log generator. 
    I need a realistic JSON dataset of received emails for the following accounts: [${accountsList}].

    Timeframe: From ${dateRange.startDate} to ${dateRange.endDate}.

    Instructions:
    1. Generate between 15 to 40 distinct email entries distributed across the timeframe.
    2. Vary the 'recipient' field among the provided accounts.
    3. Create realistic 'sender', 'subject', and 'date' fields.
    4. Subjects should vary (Newsletters, Work, Spam, Personal, bills).
    5. Return ONLY the JSON array.

    Output Schema:
    Array<{
      date: string (YYYY-MM-DD),
      sender: string,
      subject: string,
      recipient: string
    }>
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              sender: { type: Type.STRING },
              subject: { type: Type.STRING },
              recipient: { type: Type.STRING }
            },
            required: ["date", "sender", "subject", "recipient"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);
    return parsed.map((item: any, index: number) => ({
      ...item,
      id: `email-${Date.now()}-${index}`
    }));
  } catch (error) {
    console.error("Failed to generate simulated email data", error);
    throw new Error("Could not connect to mail servers. Please check credentials and try again.");
  }
};

export const generateAnalysisSummary = async (emails: EmailRecord[], startDate: string, endDate: string): Promise<string> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview";

  const emailContext = JSON.stringify(emails.slice(0, 50)); 

  const prompt = `
    Analyze this list of emails received between ${startDate} and ${endDate}.
    Provide a brief, professional summary of the volume patterns across the accounts.
    Mention which account received the most traffic if there are multiple.
    Keep it under 3 sentences.

    Email Data Sample:
    ${emailContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error("Analysis failed", error);
    return "Could not generate AI insights at this time.";
  }
};

import React, { useState } from 'react';
import { Account, LoadingState } from '../types';
import { Plus, Trash2, Shield, Globe, Server, Play, AlertCircle } from 'lucide-react';

interface AccountInputProps {
  onFetch: (accounts: Account[]) => void;
  loadingState: LoadingState;
}

const PROVIDERS: Record<string, string> = {
  'gmail.com': 'Google Mail',
  'outlook.com': 'Outlook',
  'hotmail.com': 'Outlook',
  'yahoo.com': 'Yahoo Mail',
  'icloud.com': 'iCloud',
  'proton.me': 'ProtonMail',
};

const detectProvider = (email: string) => {
  if (!email.includes('@')) return 'Unknown';
  const domain = email.split('@')[1].toLowerCase();
  return PROVIDERS[domain] || domain;
};

export const AccountInput: React.FC<AccountInputProps> = ({ onFetch, loadingState }) => {
  const [accounts, setAccounts] = useState<Account[]>([
    { id: '1', email: '', password: '', provider: 'Unknown' }
  ]);

  const [logs, setLogs] = useState<string[]>([]);

  const updateAccount = (id: string, field: keyof Account, value: string) => {
    setAccounts(prev => prev.map(acc => {
      if (acc.id === id) {
        const updated = { ...acc, [field]: value };
        if (field === 'email') {
          updated.provider = detectProvider(value);
        }
        return updated;
      }
      return acc;
    }));
  };

  const addRow = () => {
    setAccounts(prev => [
      ...prev, 
      { id: Date.now().toString(), email: '', password: '', provider: 'Unknown' }
