import React, { useState, useEffect, useMemo } from 'react';
import { AccountInput } from './components/AccountInput';
import { DateFilter } from './components/DateFilter';
import { Dashboard } from './components/Dashboard';
import { fetchSimulatedEmails, generateAnalysisSummary } from './services/geminiService';
import { EmailRecord, DateRange, AnalysisSummary, LoadingState, Account } from './types';
import { LayoutDashboard } from 'lucide-react';

const App: React.FC = () => {
  const [emails, setEmails] = useState<EmailRecord[]>([]);
  const [accounts, setAccounts] = useState<Account[]>([]);

  // Default range: Last 7 days
  const [dateRange, setDateRange] = useState<DateRange>({
    startDate: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0]
  });

  const [summary, setSummary] = useState<AnalysisSummary | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);

  const handleFetch = async (accountList: Account[]) => {
    setLoadingState(LoadingState.PARSING);
    setAccounts(accountList); // Store accounts for context

    try {
      // Pass the current date range request to the simulator
      const fetchedEmails = await fetchSimulatedEmails(accountList, dateRange);
      setEmails(fetchedEmails);

      setLoadingState(LoadingState.SUCCESS);
    } catch (error) {
      setLoadingState(LoadingState.ERROR);
    }
  };

  // Filter emails based on range (client-side filtering as well, in case simulation returns broader data)
  const filteredEmails = useMemo(() => {
    const start = new Date(dateRange.startDate).getTime();
    const end = new Date(dateRange.endDate).getTime();

    return emails.filter(email => {
      const emailDate = new Date(email.date).getTime();
      return emailDate >= start && emailDate <= end;
    });
  }, [emails, dateRange]);

  // Run analysis when filtered emails change
  useEffect(() => {
    const runAnalysis = async () => {
      if (filteredEmails.length === 0) {
        setSummary(null);
        return;
      }

      setLoadingState(LoadingState.ANALYZING);

      // Basic stats calculation (Synchronous)
      const dayCounts = new Map<string, number>();
      filteredEmails.forEach(e => {
         dayCounts.set(e.date, (dayCounts.get(e.date) || 0) + 1);
      });

      const uniqueDays = dayCounts.size || 1; // Avoid divide by zero
      const dailyAvg = filteredEmails.length / uniqueDays;

      let busiestDay = '';
      let maxCount = 0;
      dayCounts.forEach((count, day) => {
        if (count > maxCount) {
          maxCount = count;
          busiestDay = day;
        }
      });

      // AI Summary (Asynchronous)
      try {
        const aiText = await generateAnalysisSummary(filteredEmails, dateRange.startDate, dateRange.endDate);

        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: aiText
        });
        setLoadingState(LoadingState.SUCCESS);
      } catch (err) {
        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: "AI analysis unavailable."
        });
        setLoadingState(LoadingState.SUCCESS);
      }
    };

    const timeoutId = setTimeout(() => {
        runAnalysis();
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [filteredEmails, dateRange]);

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-12">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
               <LayoutDashboard className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-700 to-indigo-500 bg-clip-text text-transparent">
              MailPulse Analytics
            </h1>
          </div>
          <div className="text-sm text-slate-500">
             Powered by Gemini 3
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="lg:col-span-4 space-y-6">
            <AccountInput onFetch={handleFetch} loadingState={loadingState} />
            <DateFilter dateRange={dateRange} onDateChange={setDateRange} />
          </div>

          {/* Right Column: Dashboard */}
          <div className="lg:col-span-8">
             <Dashboard 
                filteredEmails={filteredEmails} 
                summary={summary} 
                loadingState={loadingState} 
             />
          </div>

        </div>

      </main>
    </div>
  );
};

export default App;

export interface EmailRecord {
  id: string;
  date: string; // ISO String YYYY-MM-DD
  subject: string;
  sender: string;
  recipient: string; // The account that received this email
  folder: 'Inbox' | 'Spam';
}

export interface Account {
  id: string;
  email: string;
  password: string;
  provider: string;
}

export interface DateRange {
  startDate: string;
  endDate: string;
}

export interface AnalysisSummary {
  totalCount: number;
  dailyAverage: number;
  busiestDay: string;
  aiInsights: string;
}

export enum LoadingState {
  IDLE = 'IDLE',
  PARSING = 'PARSING',
  ANALYZING = 'ANALYZING',
  ERROR = 'ERROR',
  SUCCESS = 'SUCCESS'
}

import { GoogleGenAI, Type } from "@google/genai";
import { EmailRecord, Account, DateRange } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

// Since we cannot actually access IMAP servers from a browser client without a backend proxy,
// we use Gemini to simulate the "fetching" process and generate realistic data based on the accounts provided.
export const fetchSimulatedEmails = async (accounts: Account[], dateRange: DateRange): Promise<EmailRecord[]> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview"; 

  const accountsList = accounts.map(a => `${a.email} (${a.provider})`).join(', ');

  const prompt = `
    Act as a mail server log generator. 
    I need a realistic JSON dataset of received emails for the following accounts: [${accountsList}].

    Timeframe: From ${dateRange.startDate} to ${dateRange.endDate}.

    Instructions:
    1. Generate between 20 to 50 distinct email entries distributed across the timeframe.
    2. Vary the 'recipient' field among the provided accounts.
    3. Include emails from both 'Inbox' and 'Spam' folders. Use a 'folder' field to specify.
    4. FILTERING RULE: Do NOT generate administrative or system emails from the email provider itself (e.g., if the account is gmail.com, do NOT include emails from google.com, gmail team, or security alerts). We only want user-centric mail (newsletters, spam, personal, business).
    5. Return ONLY the JSON array.

    Output Schema:
    Array<{
      date: string (YYYY-MM-DD),
      sender: string,
      subject: string,
      recipient: string,
      folder: 'Inbox' | 'Spam'
    }>
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              sender: { type: Type.STRING },
              subject: { type: Type.STRING },
              recipient: { type: Type.STRING },
              folder: { type: Type.STRING, enum: ['Inbox', 'Spam'] }
            },
            required: ["date", "sender", "subject", "recipient", "folder"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);
    return parsed.map((item: any, index: number) => ({
      ...item,
      id: `email-${Date.now()}-${index}`
    }));
  } catch (error) {
    console.error("Failed to generate simulated email data", error);
    throw new Error("Could not connect to mail servers. Please check credentials and try again.");
  }
};

export const generateAnalysisSummary = async (emails: EmailRecord[], startDate: string, endDate: string): Promise<string> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview";

  const emailContext = JSON.stringify(emails.slice(0, 50)); 

  const prompt = `
    Analyze this list of emails received between ${startDate} and ${endDate}.
    Provide a brief, professional summary of the volume patterns across the accounts.
    Mention which account received the most traffic and if there is a high volume of spam.
    Keep it under 3 sentences.

    Email Data Sample:
    ${emailContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error("Analysis failed", error);
    return "Could not generate AI insights at this time.";
  }
};

import React, { useState, useEffect } from 'react';
