import React, { useState, useEffect, useRef } from 'react';
import { Account, LoadingState } from '../types';
import { Plus, Trash2, Shield, Globe, Server, Play, AlertCircle, Save, Upload } from 'lucide-react';
import * as XLSX from 'xlsx';

interface AccountInputProps {
  onFetch: (accounts: Account[]) => void;
  loadingState: LoadingState;
}

const PROVIDERS: Record<string, string> = {
  'gmail.com': 'Google Mail',
  'outlook.com': 'Outlook',
  'hotmail.com': 'Outlook',
  'yahoo.com': 'Yahoo Mail',
  'icloud.com': 'iCloud',
  'proton.me': 'ProtonMail',
};

const detectProvider = (email: string) => {
  if (!email.includes('@')) return 'Unknown';
  const domain = email.split('@')[1].toLowerCase();
  return PROVIDERS[domain] || domain;
};

const STORAGE_KEY = 'mailpulse_accounts_v1';

export const AccountInput: React.FC<AccountInputProps> = ({ onFetch, loadingState }) => {
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [logs, setLogs] = useState<string[]>([]);
  const [loaded, setLoaded] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load from LocalStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setAccounts(JSON.parse(saved));
      } catch (e) {
        setAccounts([{ id: '1', email: '', password: '', provider: 'Unknown' }]);
      }
    } else {
      setAccounts([{ id: '1', email: '', password: '', provider: 'Unknown' }]);
    }
    setLoaded(true);
  }, []);

  // Save to LocalStorage whenever accounts change
  useEffect(() => {
    if (loaded) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(accounts));
    }
  }, [accounts, loaded]);

  const updateAccount = (id: string, field: keyof Account, value: string) => {
    setAccounts(prev => prev.map(acc => {
      if (acc.id === id) {
        const updated = { ...acc, [field]: value };
        if (field === 'email') {
          updated.provider = detectProvider(value);
        }
        return updated;
      }
      return acc;
    }));
  };

  const addRow = () => {
    setAccounts(prev => [
      ...prev, 
      { id: Date.now().toString(), email: '', password: '', provider: 'Unknown' }
    ]);
  };

  const removeRow = (id: string) => {
    if (accounts.length > 1) {
      setAccounts(prev => prev.filter(a => a.id !== id));
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const data = evt.target?.result;
      const wb = XLSX.read(data, { type: 'array' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const jsonData = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

      const newAccounts: Account[] = [];

      jsonData.forEach((row, index) => {
        if (row.length < 2) return;

        // Simple header detection: skip if first cell contains "email"
        if (index === 0 && typeof row[0] === 'string' && row[0].toLowerCase().includes('email')) {
           return;
        }

        const email = String(row[0] || '').trim();
        const password = String(row[1] || '').trim();

        if (email.includes('@')) {
           newAccounts.push({
             id: Date.now().toString() + Math.random().toString(),
             email,
             password,
             provider: detectProvider(email)
           });
        }
      });

      if (newAccounts.length > 0) {
        setAccounts(prev => {
             // If the only item is empty default, replace it
             if (prev.length === 1 && !prev[0].email && !prev[0].password) {
                 return newAccounts;
             }
             return [...prev, ...newAccounts];
        });
      }
    };
    reader.readAsArrayBuffer(file);
    e.target.value = ''; // Reset to allow same file upload
  };

  const isValid = accounts.every(a => a.email.includes('@') && a.password.length > 0);
  const isProcessing = loadingState === LoadingState.PARSING;

  // Simulate logs during processing
  useEffect(() => {
    if (isProcessing) {
      setLogs([]);
      const messages = [
        "Resolving DNS for mail servers...",
        "Initiating TLS handshake...",
        "Authenticating with provided credentials...",
        "Scanning INBOX folder...",
        "Scanning SPAM folder...",
        "Filtering provider notifications...",
        "Retrieving message headers...",
        "Closing connection."
      ];
      let i = 0;
      const interval = setInterval(() => {
        if (i < messages.length) {
          setLogs(prev => [...prev, messages[i]]);
          i++;
        } else {
          clearInterval(interval);
        }
      }, 600);
      return () => clearInterval(interval);
    } else {
      setLogs([]);
    }
  }, [isProcessing]);

  if (!loaded) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
          <Server className="w-5 h-5 text-indigo-600" />
          Account Management
        </h2>
        <div className="flex items-center gap-1 text-xs text-amber-600 bg-amber-50 px-2 py-1 rounded-md border border-amber-100">
          <Shield className="w-3 h-3" />
          <span>Simulation Mode</span>
        </div>
      </div>

      <p className="text-sm text-slate-500 mb-6">
        Add the email accounts you wish to analyze. Your credentials are securely saved locally for this session.
        Upload an Excel/CSV file (Column A: Email, Column B: Password) to bulk import.
      </p>

      <div className="overflow-hidden border border-slate-200 rounded-lg mb-6">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left min-w-[600px]">
            <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
              <tr>
                <th className="px-4 py-3 min-w-[200px]">Email Address</th>
                <th className="px-4 py-3 w-[180px]">Password / App Token</th>
                <th className="px-4 py-3 w-[150px]">Detected Provider</th>
                <th className="px-4 py-3 w-[60px] text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {accounts.map((account) => (
                <tr key={account.id} className="hover:bg-slate-50/50">
                  <td className="px-4 py-2">
                    <input 
                      type="email" 
                      placeholder="user@example.com"
                      value={account.email}
                      onChange={(e) => updateAccount(account.id, 'email', e.target.value)}
                      disabled={isProcessing}
                      className="w-full bg-transparent border-none focus:ring-0 text-slate-800 placeholder:text-slate-400"
                    />
                  </td>
                  <td className="px-4 py-2">
                    <input 
                      type="password" 
                      placeholder="••••••••••••"
                      value={account.password}
                      onChange={(e) => updateAccount(account.id, 'password', e.target.value)}
                      disabled={isProcessing}
                      className="w-full bg-transparent border-none focus:ring-0 text-slate-800 placeholder:text-slate-400"
                    />
                  </td>
                  <td className="px-4 py-2 text-slate-500">
                    <div className="flex items-center gap-2">
                      {account.provider !== 'Unknown' && <Globe className="w-3 h-3 text-indigo-400 flex-shrink-0" />}
                      <span className="truncate">{account.provider}</span>
                    </div>
                  </td>
                  <td className="px-4 py-2 text-center">
                    <button 
                      onClick={() => removeRow(account.id)}
                      disabled={accounts.length === 1 || isProcessing}
                      className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors disabled:opacity-30"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="bg-slate-50 px-4 py-2 border-t border-slate-200 flex items-center justify-between">
          <button 
            onClick={addRow}
            disabled={isProcessing}
            className="flex items-center gap-1.5 text-xs font-medium text-indigo-600 hover:text-indigo-700 disabled:opacity-50"
          >
            <Plus className="w-4 h-4" />
            Add Another Account
          </button>

          <div className="flex items-center">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".xlsx,.xls,.csv" 
              onChange={handleFileUpload}
            />
            <button 
              onClick={handleImportClick}
              disabled={isProcessing}
              className="flex items-center gap-1.5 text-xs font-medium text-slate-600 hover:text-slate-800 disabled:opacity-50 hover:underline"
            >
              <Upload className="w-4 h-4" />
              Import from Excel
            </button>
          </div>
        </div>
      </div>

      {isProcessing && (
        <div className="mb-6 bg-slate-900 rounded-lg p-4 font-mono text-xs text-green-400 h-32 overflow-y-auto">
          {logs.map((log, i) => (
            <div key={i} className="mb-1">> {log}</div>
          ))}
          <div className="animate-pulse">> _</div>
        </div>
      )}

      <div className="flex justify-between items-center gap-3">
        <div className="text-xs text-slate-400 flex items-center gap-1">
          <Save className="w-3 h-3" />
          <span>Auto-saved locally</span>
        </div>

        <div className="flex items-center gap-3">
           {loadingState === LoadingState.ERROR && (
             <div className="flex items-center gap-2 text-sm text-red-600 bg-red-50 px-3 py-2 rounded-lg">
               <AlertCircle className="w-4 h-4" />
               <span>Connection failed. Please check credentials.</span>
             </div>
          )}

          <button
            onClick={() => onFetch(accounts)}
            disabled={!isValid || isProcessing}
            className={`
              flex items-center gap-2 px-6 py-2.5 rounded-lg font-medium text-white transition-all
              ${!isValid || isProcessing
                ? 'bg-slate-300 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 shadow-md hover:shadow-lg transform active:scale-95'}
            `}
          >
            {isProcessing ? (
              <>
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                Connecting...
              </>
            ) : (
              <>
                <Play className="w-4 h-4 fill-current" />
                Fetch & Analyze
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

