import { GoogleGenAI, Type } from "@google/genai";
import { EmailRecord, Account, DateRange } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }
  return new GoogleGenAI({ apiKey });
};

// Since we cannot actually access IMAP servers from a browser client without a backend proxy,
// we use Gemini to simulate the "fetching" process and generate realistic data based on the accounts provided.
export const fetchSimulatedEmails = async (accounts: Account[], dateRange: DateRange): Promise<EmailRecord[]> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview"; 

  const accountsList = accounts.map(a => `${a.email} (${a.provider})`).join(', ');

  // Dynamic volume calculation: Ensure we have enough data points per account to look realistic
  const minEmails = Math.max(20, accounts.length * 8);
  const maxEmails = Math.max(60, accounts.length * 15);

  const prompt = `
    Act as a mail server log generator. 
    I need a realistic JSON dataset of received emails for the following accounts: [${accountsList}].

    Timeframe: From ${dateRange.startDate} to ${dateRange.endDate}.

    Instructions:
    1. Generate between ${minEmails} to ${maxEmails} distinct email entries distributed across the timeframe.
    2. Ensure EVERY provided account receives emails.
    3. FOLDER SCANNING (Important): Simulate scanning international folder names.
       - Scan "Inbox", "Posteingang" (German), "INBOX" -> Map these to 'Inbox' or 'Posteingang'
       - Scan "Spam", "Junk", "Junk-E-Mail", "Spamverdacht" (German) -> Map these to 'Spam'
    4. FILTERING RULE: Do NOT generate administrative or system emails from the email provider itself (e.g., if the account is gmail.com, do NOT include emails from google.com, gmail team, or security alerts). We only want user-centric mail (newsletters, spam, personal, business).
    5. Return ONLY the JSON array.

    Output Schema:
    Array<{
      date: string (YYYY-MM-DD),
      sender: string,
      subject: string,
      recipient: string,
      folder: string
    }>
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              sender: { type: Type.STRING },
              subject: { type: Type.STRING },
              recipient: { type: Type.STRING },
              folder: { type: Type.STRING }
            },
            required: ["date", "sender", "subject", "recipient", "folder"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);
    return parsed.map((item: any, index: number) => ({
      ...item,
      id: `email-${Date.now()}-${index}`
    }));
  } catch (error) {
    console.error("Failed to generate simulated email data", error);
    throw new Error("Could not connect to mail servers. Please check credentials and try again.");
  }
};

export const generateAnalysisSummary = async (emails: EmailRecord[], startDate: string, endDate: string): Promise<string> => {
  const ai = getAiClient();
  const model = "gemini-3-flash-preview";

  const emailContext = JSON.stringify(emails.slice(0, 50)); 

  const prompt = `
    Analyze this list of emails received between ${startDate} and ${endDate}.
    Provide a brief, professional summary of the volume patterns across the accounts.
    Mention which account received the most traffic and if there is a high volume of spam (look for 'Spam', 'Junk', 'Spamverdacht').
    Keep it under 3 sentences.

    Email Data Sample:
    ${emailContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error("Analysis failed", error);
    return "Could not generate AI insights at this time.";
  }
};

