      // Phishing emails often spoof the provider (e.g. fake "web.de security alert" in Spam folder).
      // We MUST count these in the "Spam" totals.
      const folderLower = email.folder.toLowerCase();
      const isSpam = folderLower.includes('spam') || 
                     folderLower.includes('junk') || 
                     folderLower.includes('verdacht') || 
                     folderLower.includes('pourriel') ||
                     folderLower.includes('quarant');

      if (isSpam) return true;

      // 3. Provider System Mail Filter (Only applies to legitimate Inbox/other folders)
      // Exclude administrative emails from the provider itself (e.g. web.de sending to web.de)
      const recipientDomain = email.recipient.split('@')[1]?.toLowerCase();

      // If we can't parse domain, keep it (safe default)
