                 senderName.includes('vorteil') ||
                 senderName.includes('club') ||
                 senderName.includes('sicherheit') ||
                 senderName.includes('member') ||
                 senderName.includes('mailings')) {
                  return false;
             }
          }
      }

      // Generic Provider Filter: If sender domain matches recipient domain AND looks like admin
      if (senderLower.includes(recipientDomain)) {
          const senderName = senderLower.split('@')[0];
          const systemNames = ['admin', 'support', 'team', 'service', 'notification', 'noreply', 'no-reply', 'mailer-daemon', 'postmaster'];
          if (systemNames.some(s => senderName.includes(s))) return false;
