        <div className="flex items-start gap-3">
          <Lightbulb className="w-6 h-6 text-indigo-600 flex-shrink-0 mt-1" />
          <div className="flex-1">
            <h3 className="text-indigo-900 font-semibold mb-1">AI Insights</h3>
