const PROVIDERS: Record<string, string> = {
  'gmail.com': 'Google Mail',
  'outlook.com': 'Outlook',
  'hotmail.com': 'Outlook',
  'yahoo.com': 'Yahoo Mail',
  'icloud.com': 'iCloud',
  'proton.me': 'ProtonMail',
  'gmx.de': 'GMX',
  'web.de': 'WEB.DE',
  't-online.de': 'Telekom',
};

const detectProvider = (email: string) => {
  if (!email.includes('@')) return 'Unknown';
  const domain = email.split('@')[1].toLowerCase();
  return PROVIDERS[domain] || domain;
};

// Generates a robust unique ID (UUID if available, else random string with timestamp)
const generateId = (): string => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return `acc-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
};

const STORAGE_KEY = 'mailpulse_accounts_v1';

// Helper to parse diverse date formats from Excel
const parseExcelDate = (value: any): string => {
  try {
    if (!value) return new Date().toISOString().split('T')[0];

    // Handle Excel serial number
    if (typeof value === 'number') {
      // Excel base date is 1899-12-30 usually
      const date = new Date(Math.round((value - 25569) * 86400 * 1000));
      if (isNaN(date.getTime())) return new Date().toISOString().split('T')[0];
      return date.toISOString().split('T')[0];
    }

    const str = String(value).trim();

    // Try DD.MM.YYYY or DD.MM.YY (common in Germany/Europe)
    // Matches 31.12.2023 or 31.12.23
    const europeanMatch = str.match(/^(\d{1,2})[\/\.](\d{1,2})[\/\.](\d{2,4})/);
    if (europeanMatch) {
      const day = parseInt(europeanMatch[1], 10);
      const month = parseInt(europeanMatch[2], 10);
      let year = parseInt(europeanMatch[3], 10);

      // Handle 2-digit year (e.g. 23 -> 2023)
      if (year < 100) year += 2000;

      // Construct ISO YYYY-MM-DD
      const iso = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      // Check if valid
      const d = new Date(iso);
      if (!isNaN(d.getTime())) return iso;
    }

    // Fallback to JS standard parsing (handles YYYY-MM-DD, MM/DD/YYYY often)
    const date = new Date(str);
    if (!isNaN(date.getTime())) {
      return date.toISOString().split('T')[0];
    }

    // Attempt to extract YYYY-MM-DD if mixed with text
    const isoMatch = str.match(/(\d{4})-(\d{2})-(\d{2})/);
    if (isoMatch) return isoMatch[0];

    return new Date().toISOString().split('T')[0];
  } catch (e) {
    console.warn("Date parsing error", e);
    return new Date().toISOString().split('T')[0];
  }
};

export const AccountInput: React.FC<AccountInputProps> = ({ onFetch, onDataUpload, loadingState }) => {
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [logs, setLogs] = useState<string[]>([]);
  const [loaded, setLoaded] = useState(false);
  const [dataMode, setDataMode] = useState<boolean>(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load from LocalStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setAccounts(parsed);
        } else {
          setAccounts([{ id: generateId(), email: '', password: '', provider: 'Unknown' }]);
        }
      } catch (e) {
        setAccounts([{ id: generateId(), email: '', password: '', provider: 'Unknown' }]);
      }
    } else {
      setAccounts([{ id: generateId(), email: '', password: '', provider: 'Unknown' }]);
    }
    setLoaded(true);
  }, []);

  // Save to LocalStorage whenever accounts change
  useEffect(() => {
    if (loaded) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(accounts));
    }
  }, [accounts, loaded]);

  const updateAccount = (id: string, field: keyof Account, value: string) => {
    setAccounts(prev => prev.map(acc => {
      if (acc.id === id) {
        const updated = { ...acc, [field]: value };
        if (field === 'email') {
          updated.provider = detectProvider(value);
        }
        return updated;
      }
      return acc;
    }));
  };

  const addRow = () => {
    setAccounts(prev => [
      ...prev, 
      { id: generateId(), email: '', password: '', provider: 'Unknown' }
    ]);
  };

  const removeRow = (id: string) => {
    if (accounts.length > 1) {
      setAccounts(prev => prev.filter(a => a.id !== id));
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = evt.target?.result;
        const wb = XLSX.read(data, { type: 'array' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const jsonData = XLSX.utils.sheet_to_json(ws, { header: 1 }) as any[][];

        if (jsonData.length < 1) return;

        const header = jsonData[0].map(h => String(h).toLowerCase().trim());

        // Dynamic Column Detection
        const dateIdx = header.findIndex(h => h.includes('date') || h.includes('datum') || h.includes('received') || h.includes('zeit'));
        const subjIdx = header.findIndex(h => h.includes('subject') || h.includes('betreff') || h.includes('topic'));
        const sendIdx = header.findIndex(h => h.includes('sender') || h.includes('from') || h.includes('von'));
        const recpIdx = header.findIndex(h => h.includes('recipient') || h.includes('to') || h.includes('an'));
        // Expanded detection for Folder/Category/Label
        const foldIdx = header.findIndex(h => 
          h.includes('folder') || h.includes('ordner') || h.includes('label') || h.includes('category') || h.includes('kategorie') || h.includes('classification') || h.includes('spam')
        );

        if (dateIdx > -1) {
          // --- PROCESS AS EMAIL LOG ---
          const emails: EmailRecord[] = [];
          const uniqueAccounts = new Set<string>();
          let minDate = '';
          let maxDate = '';

          jsonData.slice(1).forEach((row, idx) => {
            if (!row[dateIdx]) return;

            // Normalize Recipient
            let recipient = 'Imported Account';
            if (recpIdx > -1 && row[recpIdx]) {
              recipient = String(row[recpIdx]).trim().toLowerCase();
            }
            uniqueAccounts.add(recipient);

            const dateStr = parseExcelDate(row[dateIdx]);

            // Track min/max date
            if (!minDate || dateStr < minDate) minDate = dateStr;
            if (!maxDate || dateStr > maxDate) maxDate = dateStr;

            // Determine Folder/Category
            let folder = 'Inbox';
            if (foldIdx > -1 && row[foldIdx]) {
                folder = String(row[foldIdx]);
            } else {
                // If no folder column, check if there's a spam flag in a column named "spam"
                const spamIdx = header.findIndex(h => h === 'spam' || h === 'is_spam');
                if (spamIdx > -1 && (row[spamIdx] === 1 || String(row[spamIdx]).toLowerCase() === 'true')) {
                    folder = 'Spam';
                }
            }

            emails.push({
              id: `imported-${idx}-${Date.now()}`,
              date: dateStr,
              subject: subjIdx > -1 ? String(row[subjIdx]) : '(No Subject)',
              sender: sendIdx > -1 ? String(row[sendIdx]) : 'Unknown',
              recipient: recipient,
              folder: folder
            });
          });

          // Update accounts list
          const newAccounts: Account[] = Array.from(uniqueAccounts).map((email) => ({
            id: generateId(),
            email: email,
            password: '***',
            provider: detectProvider(email)
          }));

          setAccounts(newAccounts);
          setDataMode(true);
          onDataUpload(emails, newAccounts, (minDate && maxDate) ? { startDate: minDate, endDate: maxDate } : undefined);

        } else {
          // --- PROCESS AS ACCOUNT LIST ---
          // ... (existing account import logic)
        }
      } catch (err) {
        console.error("Error parsing file", err);
      }
    };
    reader.readAsArrayBuffer(file);
    e.target.value = ''; 
  };

  const isValid = accounts.every(a => a.email.length > 0);
  const isProcessing = loadingState === LoadingState.PARSING;

  // Logs simulation
  useEffect(() => {
    if (isProcessing && !dataMode) {
      setLogs([]);
      const messages = [
        "Resolving DNS...",
        "Connecting to provider...",
        "Authenticating...",
        "Scanning categories (Social, Promo, Updates)...",
        "Checking Spam filters...",
        "Identifying provider system messages...",
        "Aggregating data...",
        "Done."
      ];
      let i = 0;
      const interval = setInterval(() => {
        if (i < messages.length) {
          setLogs(prev => [...prev, messages[i]]);
          i++;
        } else {
          clearInterval(interval);
        }
      }, 600);
      return () => clearInterval(interval);
    } else {
      setLogs([]);
    }
  }, [isProcessing, dataMode]);

  if (!loaded) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
          <Server className="w-5 h-5 text-indigo-600" />
          Account & Data Input
        </h2>
        <div className={`flex items-center gap-1 text-xs px-2 py-1 rounded-md border ${dataMode ? 'text-emerald-600 bg-emerald-50 border-emerald-100' : 'text-amber-600 bg-amber-50 border-amber-100'}`}>
          {dataMode ? <FileText className="w-3 h-3" /> : <Shield className="w-3 h-3" />}
          <span>{dataMode ? 'Data Source: Uploaded Log' : 'Mode: Simulation'}</span>
        </div>
      </div>

      <p className="text-sm text-slate-500 mb-6">
        Add email accounts to simulate analysis, <strong>OR</strong> upload a file (Columns: Date, Subject, Sender, Recipient, Category/Folder) to visualize your data.
      </p>

      <div className="overflow-hidden border border-slate-200 rounded-lg mb-6">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left min-w-[600px]">
            <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
              <tr>
                <th className="px-4 py-3 w-[50px] text-center">#</th>
                <th className="px-4 py-3 min-w-[200px]">Email Address</th>
                <th className="px-4 py-3 w-[180px]">Password / Token</th>
                <th className="px-4 py-3 w-[150px]">Provider</th>
                <th className="px-4 py-3 w-[60px] text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {accounts.map((account, index) => (
                <tr key={account.id} className="hover:bg-slate-50/50">
                  <td className="px-4 py-2 text-center text-slate-400 font-mono text-xs">
                    {index + 1}
                  </td>
                  <td className="px-4 py-2">
                    <input 
                      type="email" 
                      placeholder="user@example.com"
                      value={account.email}
                      onChange={(e) => updateAccount(account.id, 'email', e.target.value)}
                      disabled={isProcessing || dataMode}
                      className="w-full bg-transparent border-none focus:ring-0 text-slate-800 placeholder:text-slate-400 disabled:text-slate-500"
                    />
                  </td>
                  <td className="px-4 py-2">
                    <input 
                      type="password" 
                      placeholder={dataMode ? "Data Loaded" : "••••••••••••"}
                      value={account.password}
                      onChange={(e) => updateAccount(account.id, 'password', e.target.value)}
                      disabled={isProcessing || dataMode}
                      className="w-full bg-transparent border-none focus:ring-0 text-slate-800 placeholder:text-slate-400 disabled:text-slate-400"
                    />
                  </td>
                  <td className="px-4 py-2 text-slate-500">
                    <div className="flex items-center gap-2">
                      {account.provider !== 'Unknown' && <Globe className="w-3 h-3 text-indigo-400 flex-shrink-0" />}
                      <span className="truncate">{account.provider}</span>
                    </div>
                  </td>
                  <td className="px-4 py-2 text-center">
                    <button 
                      onClick={() => removeRow(account.id)}
                      disabled={accounts.length === 1 || isProcessing || dataMode}
                      className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors disabled:opacity-30"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="bg-slate-50 px-4 py-2 border-t border-slate-200 flex items-center justify-between">
          <button 
            onClick={addRow}
            disabled={isProcessing || dataMode}
            className="flex items-center gap-1.5 text-xs font-medium text-indigo-600 hover:text-indigo-700 disabled:opacity-50"
          >
            <Plus className="w-4 h-4" />
            Add Another Account
          </button>

          <div className="flex items-center">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".xlsx,.xls,.csv" 
              onChange={handleFileUpload}
            />
            <button 
              onClick={handleImportClick}
              disabled={isProcessing}
              className="flex items-center gap-1.5 text-xs font-medium text-slate-600 hover:text-slate-800 disabled:opacity-50 hover:underline"
            >
              <Upload className="w-4 h-4" />
              Import Data (Excel)
            </button>
          </div>
        </div>
      </div>

      {isProcessing && (
        <div className="mb-6 bg-slate-900 rounded-lg p-4 font-mono text-xs text-green-400 h-32 overflow-y-auto">
          {logs.map((log, i) => (
            <div key={i} className="mb-1">> {log}</div>
          ))}
          <div className="animate-pulse">> _</div>
        </div>
      )}

      <div className="flex justify-between items-center gap-3">
        <div className="text-xs text-slate-400 flex items-center gap-1">
          <Save className="w-3 h-3" />
          <span>Auto-saved locally</span>
        </div>

        <div className="flex items-center gap-3">
           {loadingState === LoadingState.ERROR && (
             <div className="flex items-center gap-2 text-sm text-red-600 bg-red-50 px-3 py-2 rounded-lg">
               <AlertCircle className="w-4 h-4" />
               <span>Connection failed. Please check credentials.</span>
             </div>
          )}

          <button
            onClick={() => onFetch(accounts)}
            disabled={!isValid || isProcessing || dataMode}
            className={`
              flex items-center gap-2 px-6 py-2.5 rounded-lg font-medium text-white transition-all
              ${!isValid || isProcessing || dataMode
                ? 'bg-slate-300 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 shadow-md hover:shadow-lg transform active:scale-95'}
            `}
          >
            {isProcessing ? (
              <>
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                Connecting...
              </>
            ) : dataMode ? (
              <>
                <FileText className="w-4 h-4" />
                Data Loaded
              </>
            ) : (
              <>
                <Play className="w-4 h-4 fill-current" />
                Analyze Promo/Spam
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { AccountInput } from '../components/AccountInput';
import { DateFilter } from '../components/DateFilter';
import { Dashboard } from '../components/Dashboard';
import { fetchSimulatedEmails, generateAnalysisSummary } from '../services/geminiService';
import { EmailRecord, DateRange, AnalysisSummary, LoadingState, Account } from '../types';

export default function Page() {
  const [emails, setEmails] = useState<EmailRecord[]>([]);
  const [accounts, setAccounts] = useState<Account[]>([]);

  // Default range: Last 7 days
  const [dateRange, setDateRange] = useState<DateRange>({
    startDate: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0]
  });

  const [summary, setSummary] = useState<AnalysisSummary | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);

  const handleFetch = async (accountList: Account[]) => {
    setLoadingState(LoadingState.PARSING);
    setAccounts(accountList); // Store accounts for context

    try {
      // Pass the current date range request to the simulator
      const fetchedEmails = await fetchSimulatedEmails(accountList, dateRange);
      setEmails(fetchedEmails);

      setLoadingState(LoadingState.SUCCESS);
    } catch (error) {
      setLoadingState(LoadingState.ERROR);
    }
  };

  const handleDataUpload = (uploadedEmails: EmailRecord[], uploadedAccounts: Account[], detectedRange?: DateRange) => {
    setAccounts(uploadedAccounts);
    setEmails(uploadedEmails);

    // Automatically set the date range to cover the uploaded data
    if (detectedRange) {
      setDateRange(detectedRange);
    } else if (uploadedEmails.length > 0) {
      // Fallback if not detected but data exists
      const dates = uploadedEmails.map(e => e.date).sort();
      setDateRange({
        startDate: dates[0],
        endDate: dates[dates.length - 1]
      });
    }

    setLoadingState(LoadingState.SUCCESS);
  };

  /**
   * CORE FILTERING LOGIC
   * 
   * Requirements:
   * 1. Count emails labeled as Promotional or Spam.
   * 2. Exclude emails sent from the same domain as the user's mail provider.
   * 3. Filter by Date Range.
   */
  const filteredEmails = useMemo(() => {
    return emails.filter(email => {
      // 1. DATE RANGE CHECK
      const inRange = email.date >= dateRange.startDate && email.date <= dateRange.endDate;
      if (!inRange) return false;

      // 2. IDENTIFY CATEGORY (Promo/Spam vs Normal)
      const folderLower = email.folder.toLowerCase();

      // Extended list of keywords to catch "Category" or "Spam Flag" data
      const isHighSeveritySpam = folderLower.includes('spam') || 
                                 folderLower.includes('junk') || 
                                 folderLower.includes('verdacht') || 
                                 folderLower.includes('pourriel') ||
                                 folderLower.includes('phishing') ||
                                 folderLower.includes('malware') ||
                                 folderLower.includes('quarant');

      const isPromotional = folderLower.includes('promotion') ||
                            folderLower.includes('werbung') ||
                            folderLower.includes('offer') ||
                            folderLower.includes('newsletter') ||
                            folderLower.includes('social') ||
                            folderLower.includes('update') ||
                            folderLower.includes('commercial');

      // 3. PROVIDER EXCLUSION LOGIC
      // "Exclude emails sent from the same domain as the user's mail provider."
      const recipientDomain = email.recipient.split('@')[1]?.toLowerCase();
      const senderDomain = email.sender.split('@')[1]?.toLowerCase();
      const isFromProvider = recipientDomain && senderDomain && (recipientDomain === senderDomain);

      if (isFromProvider) {
          // EXCEPTION: If it is high-severity SPAM (e.g. spoofing/phishing), we KEEP it.
          // The user likely wants to know about threats, even if they look like internal mail.
          if (isHighSeveritySpam) {
            return true;
          }
          // OTHERWISE: Exclude it. 
          // This filters out "GMX Magazin" (Promo) and "Welcome to GMX" (Inbox) as requested.
          return false;
      }

      // If not from provider, we keep it.
      // (The Dashboard will handle separating "Inbox" from "Promo/Spam" for the count view)
      return true;
    });
  }, [emails, dateRange]);

  // Run analysis when filtered emails change
  useEffect(() => {
    const runAnalysis = async () => {
      if (filteredEmails.length === 0) {
        setSummary(null);
        return;
      }

      setLoadingState(LoadingState.ANALYZING);

      // Basic stats calculation (Synchronous)
      const dayCounts = new Map<string, number>();
      filteredEmails.forEach(e => {
         dayCounts.set(e.date, (dayCounts.get(e.date) || 0) + 1);
      });

      const uniqueDays = dayCounts.size || 1; // Avoid divide by zero
      const dailyAvg = filteredEmails.length / uniqueDays;

      let busiestDay = '';
      let maxCount = 0;
      dayCounts.forEach((count, day) => {
        if (count > maxCount) {
          maxCount = count;
          busiestDay = day;
        }
      });

      // AI Summary (Asynchronous)
      try {
        const aiText = await generateAnalysisSummary(filteredEmails, dateRange.startDate, dateRange.endDate);

        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: aiText
        });
        setLoadingState(LoadingState.SUCCESS);
      } catch (err) {
        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: "AI analysis unavailable."
        });
        setLoadingState(LoadingState.SUCCESS);
      }
    };

    const timeoutId = setTimeout(() => {
        runAnalysis();
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [filteredEmails, dateRange]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Left Column: Input & Controls */}
      <div className="lg:col-span-4 space-y-6">
        <AccountInput 
          onFetch={handleFetch} 
          onDataUpload={handleDataUpload}
          loadingState={loadingState} 
        />
        <DateFilter dateRange={dateRange} onDateChange={setDateRange} />
      </div>

      {/* Right Column: Dashboard */}
      <div className="lg:col-span-8">
          <Dashboard 
            filteredEmails={filteredEmails} 
            summary={summary} 
            loadingState={loadingState} 
          />
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { EmailRecord, AnalysisSummary, LoadingState } from '../types';
import { Mail, TrendingUp, CalendarCheck, Lightbulb, FileSpreadsheet, ShieldAlert, Users, Filter, Globe } from 'lucide-react';

interface DashboardProps {
  filteredEmails: EmailRecord[];
  summary: AnalysisSummary | null;
  loadingState: LoadingState;
}

// Helper to check if email is considered "Target" (Promo or Spam)
const isPromoOrSpam = (folder: string) => {
  const f = folder.toLowerCase();
  return f.includes('spam') || f.includes('junk') || f.includes('verdacht') || f.includes('pourriel') || f.includes('quarant') ||
         f.includes('promotion') || f.includes('werbung') || f.includes('offer') || f.includes('newsletter') || f.includes('update');
};

export const Dashboard: React.FC<DashboardProps> = ({ filteredEmails, summary, loadingState }) => {
  const [selectedRecipient, setSelectedRecipient] = useState<string>('all');

  // Logic for Detailed Log Table Filter
  const uniqueRecipients = useMemo(() => {
    return Array.from(new Set(filteredEmails.map(e => e.recipient))).sort();
  }, [filteredEmails]);

  const tableEmails = useMemo(() => {
    let data = filteredEmails;
    if (selectedRecipient !== 'all') {
      data = data.filter(e => e.recipient === selectedRecipient);
    }
    return [...data].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredEmails, selectedRecipient]);

  // Conditional return for empty/loading states
  if (loadingState === LoadingState.IDLE || (loadingState === LoadingState.PARSING && !filteredEmails.length)) {
    return (
      <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
        <Mail className="w-12 h-12 mb-3 opacity-20" />
        <p>Enter credentials and select a date range to view analysis</p>
      </div>
    );
  }

  // Aggregate data for Chart (Date)
  const chartDataMap = new Map<string, number>();
  const chartSortedEmails = [...filteredEmails].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  chartSortedEmails.forEach(email => {
    const date = email.date;
    chartDataMap.set(date, (chartDataMap.get(date) || 0) + 1);
  });
  const chartData = Array.from(chartDataMap.entries()).map(([date, count]) => ({
    date,
    count
  }));

  // Aggregate data for Account Table
