// Helper to check if email is considered "Target" (Promo or Spam)
const isPromoOrSpam = (folder: string) => {
  const f = folder.toLowerCase();
  return f.includes('spam') || f.includes('junk') || f.includes('verdacht') || f.includes('pourriel') || f.includes('quarant') ||
         f.includes('promotion') || f.includes('werbung') || f.includes('offer') || f.includes('newsletter') || f.includes('update');
};

export const Dashboard: React.FC<DashboardProps> = ({ filteredEmails, summary, loadingState, onSelectAccount }) => {
  const [selectedRecipient, setSelectedRecipient] = useState<string>('all');

  // Logic for Detailed Log Table Filter
  const uniqueRecipients = useMemo(() => {
    return Array.from(new Set(filteredEmails.map(e => e.recipient))).sort();
  }, [filteredEmails]);

  const tableEmails = useMemo(() => {
    let data = filteredEmails;
    if (selectedRecipient !== 'all') {
      data = data.filter(e => e.recipient === selectedRecipient);
