"use client";

import React, { useState, useEffect, useMemo } from 'react';
import { AccountInput } from '../components/AccountInput';
import { DateFilter } from '../components/DateFilter';
import { Dashboard } from '../components/Dashboard';
import { AccountAnalyzer } from '../components/AccountAnalyzer';
import { fetchSimulatedEmails, generateAnalysisSummary } from '../services/geminiService';
import { EmailRecord, DateRange, AnalysisSummary, LoadingState, Account } from '../types';

export default function Page() {
  const [emails, setEmails] = useState<EmailRecord[]>([]);
  const [accounts, setAccounts] = useState<Account[]>([]);

  // Default range: Last 7 days
  const [dateRange, setDateRange] = useState<DateRange>({
    startDate: new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0],
    endDate: new Date().toISOString().split('T')[0]
  });

  const [summary, setSummary] = useState<AnalysisSummary | null>(null);
  const [loadingState, setLoadingState] = useState<LoadingState>(LoadingState.IDLE);

  // View Management
  const [view, setView] = useState<'dashboard' | 'analyzer'>('dashboard');
  const [selectedAccountEmail, setSelectedAccountEmail] = useState<string | null>(null);

  const handleFetch = async (accountList: Account[]) => {
    setLoadingState(LoadingState.PARSING);
    setAccounts(accountList); // Store accounts for context

    try {
      // Pass the current date range request to the simulator
      const fetchedEmails = await fetchSimulatedEmails(accountList, dateRange);
      setEmails(fetchedEmails);

      setLoadingState(LoadingState.SUCCESS);
      setView('dashboard'); // Reset view on new fetch
    } catch (error) {
      setLoadingState(LoadingState.ERROR);
    }
  };

  const handleDataUpload = (uploadedEmails: EmailRecord[], uploadedAccounts: Account[], detectedRange?: DateRange) => {
    setAccounts(uploadedAccounts);
    setEmails(uploadedEmails);

    // Automatically set the date range to cover the uploaded data
    if (detectedRange) {
      setDateRange(detectedRange);
    } else if (uploadedEmails.length > 0) {
      // Fallback if not detected but data exists
      const dates = uploadedEmails.map(e => e.date).sort();
      setDateRange({
        startDate: dates[0],
        endDate: dates[dates.length - 1]
      });
    }

    setLoadingState(LoadingState.SUCCESS);
    setView('dashboard');
  };

  // Switch to Analyzer View
  const handleAccountSelect = (email: string) => {
    setSelectedAccountEmail(email);
    setView('analyzer');
  };

  const handleBackToDashboard = () => {
    setSelectedAccountEmail(null);
    setView('dashboard');
  };

  /**
   * CORE FILTERING LOGIC
   */
  const filteredEmails = useMemo(() => {
    return emails.filter(email => {
      // 1. DATE RANGE CHECK
      const inRange = email.date >= dateRange.startDate && email.date <= dateRange.endDate;
      if (!inRange) return false;

      // 2. IDENTIFY CATEGORY (Promo/Spam vs Normal) - Just for reference in later logic, not filtering here.
      // We no longer filter out Provider emails silently, so the total count remains accurate to the upload.

      return true;
    });
  }, [emails, dateRange]);

  // Derived state for the specific account being analyzed
  const accountSpecificEmails = useMemo(() => {
    if (!selectedAccountEmail) return [];
    return filteredEmails.filter(e => e.recipient === selectedAccountEmail);
  }, [filteredEmails, selectedAccountEmail]);

  // Run analysis when filtered emails change
  useEffect(() => {
    const runAnalysis = async () => {
      if (filteredEmails.length === 0) {
        setSummary(null);
        return;
      }

      setLoadingState(LoadingState.ANALYZING);

      const dayCounts = new Map<string, number>();
      filteredEmails.forEach(e => {
         dayCounts.set(e.date, (dayCounts.get(e.date) || 0) + 1);
      });

      const uniqueDays = dayCounts.size || 1; 
      const dailyAvg = filteredEmails.length / uniqueDays;

      let busiestDay = '';
      let maxCount = 0;
      dayCounts.forEach((count, day) => {
        if (count > maxCount) {
          maxCount = count;
          busiestDay = day;
        }
      });

      try {
        const aiText = await generateAnalysisSummary(filteredEmails, dateRange.startDate, dateRange.endDate);

        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: aiText
        });
        setLoadingState(LoadingState.SUCCESS);
      } catch (err) {
        setSummary({
          totalCount: filteredEmails.length,
          dailyAverage: dailyAvg,
          busiestDay: busiestDay || 'N/A',
          aiInsights: "AI analysis unavailable."
        });
        setLoadingState(LoadingState.SUCCESS);
      }
    };

    const timeoutId = setTimeout(() => {
        runAnalysis();
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [filteredEmails, dateRange]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Left Column: Input & Controls (Always visible, but maybe disabled/hidden logic could be applied if deep diving) */}
      <div className={`lg:col-span-4 space-y-6 ${view === 'analyzer' ? 'hidden lg:block' : ''}`}>
        <AccountInput 
          onFetch={handleFetch} 
          onDataUpload={handleDataUpload}
          loadingState={loadingState} 
        />
        <DateFilter dateRange={dateRange} onDateChange={setDateRange} />
      </div>

      {/* Right Column: Dashboard or Analyzer */}
      <div className={`${view === 'analyzer' ? 'lg:col-span-12' : 'lg:col-span-8'}`}>
          {view === 'dashboard' ? (
            <Dashboard 
              filteredEmails={filteredEmails} 
              summary={summary} 
              loadingState={loadingState} 
              onSelectAccount={handleAccountSelect}
            />
          ) : (
            <div className="bg-slate-50/50">
               <AccountAnalyzer 
                  email={selectedAccountEmail || ''}
                  data={accountSpecificEmails}
                  onBack={handleBackToDashboard}
               />
            </div>
          )}
      </div>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { EmailRecord } from '../types';
import { ArrowLeft, ShieldAlert, Mail, Globe, Users, TrendingUp, Search, FolderOpen, PieChart } from 'lucide-react';
import { BarChart, Bar, XAxis, Tooltip, ResponsiveContainer, Cell, PieChart as RePieChart, Pie, Cell as PieCell, Legend } from 'recharts';

interface AccountAnalyzerProps {
  email: string;
  data: EmailRecord[];
  onBack: () => void;
}

const isPromoOrSpam = (folder: string) => {
  const f = folder.toLowerCase();
  return f.includes('spam') || f.includes('junk') || f.includes('verdacht') || 
         f.includes('promotion') || f.includes('werbung') || f.includes('offer') || f.includes('newsletter');
};

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#3b82f6'];

export const AccountAnalyzer: React.FC<AccountAnalyzerProps> = ({ email, data, onBack }) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Domain Extraction
  const domain = email.includes('@') ? email.split('@')[1] : 'Unknown Domain';
  const providerName = domain.split('.')[0].charAt(0).toUpperCase() + domain.split('.')[0].slice(1);

  // Stats
  const stats = useMemo(() => {
    let spamCount = 0;
    const senders = new Set<string>();
    const senderDomains = new Map<string, number>();
    const folderCounts = new Map<string, number>();

    data.forEach(e => {
      // Spam Count
      if (isPromoOrSpam(e.folder)) spamCount++;

      // Sender Unique
      senders.add(e.sender);

      // Top Domains
      const sDomain = e.sender.includes('@') ? e.sender.split('@')[1].toLowerCase() : 'unknown';
      senderDomains.set(sDomain, (senderDomains.get(sDomain) || 0) + 1);

      // Folder Counts (Raw)
      const fName = e.folder || 'Unknown';
      folderCounts.set(fName, (folderCounts.get(fName) || 0) + 1);
    });

    const topDomains = Array.from(senderDomains.entries())
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    const folderStats = Array.from(folderCounts.entries())
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);

    return {
      total: data.length,
      spam: spamCount,
      uniqueSenders: senders.size,
      topDomains,
      folderStats
    };
  }, [data]);

  // Chart Data (Time Series)
  const chartData = useMemo(() => {
    const map = new Map<string, number>();
    data.forEach(e => {
      map.set(e.date, (map.get(e.date) || 0) + 1);
    });
    return Array.from(map.entries())
      .map(([date, count]) => ({ date, count }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [data]);

  // Filtered List
  const filteredList = useMemo(() => {
    if (!searchTerm) return data;
    const lower = searchTerm.toLowerCase();
    return data.filter(e => 
      e.subject.toLowerCase().includes(lower) || 
      e.sender.toLowerCase().includes(lower) ||
      e.folder.toLowerCase().includes(lower)
    );
  }, [data, searchTerm]);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500"
        >
          <ArrowLeft className="w-6 h-6" />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{email}</h2>
          <div className="flex items-center gap-2 text-sm text-slate-500">
            <Globe className="w-3 h-3" />
            <span>Domain: <span className="font-medium text-indigo-600">{domain}</span></span>
          </div>
        </div>
      </div>

      {/* KPI Cards */}
