import React, { useState, useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { EmailRecord, AnalysisSummary, LoadingState } from '../types';
import { Mail, TrendingUp, CalendarCheck, Lightbulb, FileSpreadsheet, ShieldAlert, Users, Filter, Globe, ArrowRight } from 'lucide-react';

interface DashboardProps {
  filteredEmails: EmailRecord[];
  summary: AnalysisSummary | null;
  loadingState: LoadingState;
  onSelectAccount?: (email: string) => void;
}

// Helper to check if email is considered "Target" (Promo or Spam)
const isPromoOrSpam = (folder: string) => {
  const f = folder.toLowerCase();
  // EXPLICIT EXCLUSION: "Unbekannt" (Unknown) and "Allgemein" (General) are often Inbox-adjacent in Germany, not Spam.
  if (f.includes('allgemein') || f.includes('unbekannt') || f.includes('posteingang')) return false;

  return f.includes('spam') || f.includes('junk') || f.includes('verdacht') || f.includes('pourriel') || f.includes('quarant') ||
         f.includes('promotion') || f.includes('werbung') || f.includes('offer') || f.includes('newsletter') || f.includes('update') ||
         f.includes('unerwünscht') || f.includes('abgelehnt');
};

export const Dashboard: React.FC<DashboardProps> = ({ filteredEmails, summary, loadingState, onSelectAccount }) => {
  const [selectedRecipient, setSelectedRecipient] = useState<string>('all');

  // Logic for Detailed Log Table Filter
  const uniqueRecipients = useMemo(() => {
    return Array.from(new Set(filteredEmails.map(e => e.recipient))).sort();
  }, [filteredEmails]);

  const tableEmails = useMemo(() => {
    let data = filteredEmails;
    if (selectedRecipient !== 'all') {
      data = data.filter(e => e.recipient === selectedRecipient);
    }
    return [...data].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredEmails, selectedRecipient]);

  // Conditional return for empty/loading states
  if (loadingState === LoadingState.IDLE || (loadingState === LoadingState.PARSING && !filteredEmails.length)) {
    return (
      <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-slate-400 border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
        <Mail className="w-12 h-12 mb-3 opacity-20" />
        <p>Enter credentials and select a date range to view analysis</p>
      </div>
    );
  }

  // Aggregate data for Chart (Date)
  const chartDataMap = new Map<string, number>();
  const chartSortedEmails = [...filteredEmails].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  chartSortedEmails.forEach(email => {
    const date = email.date;
    chartDataMap.set(date, (chartDataMap.get(date) || 0) + 1);
  });
  const chartData = Array.from(chartDataMap.entries()).map(([date, count]) => ({
    date,
    count
  }));

  // Aggregate data for Account Table
  const accountStats = new Map<string, { total: number, inbox: number, promoSpam: number }>();
  filteredEmails.forEach(email => {
    const stats = accountStats.get(email.recipient) || { total: 0, inbox: 0, promoSpam: 0 };
    stats.total++;

    if (isPromoOrSpam(email.folder)) {
      stats.promoSpam++;
    } else {
      stats.inbox++;
    }
    accountStats.set(email.recipient, stats);
  });

  const accountStatsArray = Array.from(accountStats.entries()).map(([email, stats]) => ({
    email,
    ...stats
  })).sort((a, b) => b.promoSpam - a.promoSpam); // Sort by Promo/Spam volume

  // Aggregate data for Domain Breakdown (Requirement: "Optional breakdown by sender domain")
  const domainStats = new Map<string, number>();
  filteredEmails.forEach(email => {
    // We break down ALL traffic, but emphasize Promo/Spam
    if (isPromoOrSpam(email.folder)) {
       const domain = email.sender.includes('@') ? email.sender.split('@')[1].toLowerCase() : 'unknown';
       domainStats.set(domain, (domainStats.get(domain) || 0) + 1);
    }
  });
  const domainStatsArray = Array.from(domainStats.entries())
    .map(([domain, count]) => ({ domain, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 6); // Top 6

  const isAnalyzing = loadingState === LoadingState.ANALYZING;

  return (
    <div className="space-y-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-50 rounded-lg">
              <Mail className="w-5 h-5 text-blue-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Total Analyzed</h3>
          </div>
          <p className="text-2xl font-bold text-slate-800">{filteredEmails.length}</p>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-orange-50 rounded-lg">
              <ShieldAlert className="w-5 h-5 text-orange-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Promo & Spam</h3>
          </div>
          <p className="text-2xl font-bold text-slate-800">
            {filteredEmails.filter(e => isPromoOrSpam(e.folder)).length}
          </p>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-purple-50 rounded-lg">
              <CalendarCheck className="w-5 h-5 text-purple-600" />
            </div>
            <h3 className="text-sm font-medium text-slate-500">Busiest Day</h3>
          </div>
          <p className="text-lg font-bold text-slate-800 truncate">
             {summary ? summary.busiestDay : '-'}
          </p>
        </div>
      </div>

      {/* AI Summary */}
      <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100">
        <div className="flex items-start gap-3">
          <Lightbulb className="w-6 h-6 text-indigo-600 flex-shrink-0 mt-1" />
          <div className="flex-1">
            <h3 className="text-indigo-900 font-semibold mb-1">AI Insights</h3>
            {isAnalyzing ? (
               <div className="h-4 bg-indigo-200/50 rounded animate-pulse w-3/4 mt-2"></div>
            ) : (
              <p className="text-indigo-800 text-sm leading-relaxed">
                {summary?.aiInsights || "Generate data to see AI-powered insights regarding your email traffic."}
              </p>
            )}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Account Volume Table */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
          <div className="p-6 border-b border-slate-200">
            <h3 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
              <Users className="w-5 h-5 text-indigo-600" />
              Volume by Account
            </h3>
          </div>
          <div className="overflow-y-auto max-h-[300px]">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200 sticky top-0">
                <tr>
                  <th className="px-6 py-3">Account</th>
                  <th className="px-6 py-3 text-right">Inbox</th>
                  <th className="px-6 py-3 text-right text-orange-600">Promo/Spam</th>
                  <th className="px-6 py-3 text-right text-slate-800">Total</th>
                  <th className="px-6 py-3 text-right">Action</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {accountStatsArray.map((stat, idx) => (
                  <tr 
                    key={idx} 
                    className="hover:bg-slate-50 cursor-pointer group"
                    onClick={() => onSelectAccount && onSelectAccount(stat.email)}
                  >
                    <td className="px-6 py-3 font-medium text-slate-700 truncate max-w-[180px]" title={stat.email}>
                      {stat.email}
                    </td>
                    <td className="px-6 py-3 text-right text-slate-500">
                      {stat.inbox}
                    </td>
                    <td className="px-6 py-3 text-right text-orange-600 font-medium">
                      {stat.promoSpam}
                    </td>
                    <td className="px-6 py-3 text-right font-bold text-slate-800">
                      {stat.total}
                    </td>
                    <td className="px-6 py-3 text-right">
                       <div className="flex justify-end">
                         <div className="p-1.5 rounded-full bg-slate-100 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600 transition-colors">
                            <ArrowRight className="w-4 h-4" />
                         </div>
                       </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Sender Domain Breakdown */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
           <div className="p-6 border-b border-slate-200">
            <h3 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
              <Globe className="w-5 h-5 text-indigo-600" />
              Top Sender Domains (Promo/Spam)
            </h3>
          </div>
          <div className="p-6 overflow-y-auto max-h-[300px]">
             {domainStatsArray.length > 0 ? (
               <div className="space-y-4">
                 {domainStatsArray.map((item, idx) => (
                   <div key={idx} className="flex items-center gap-4">
                     <span className="text-slate-400 font-mono text-xs w-4">{idx + 1}</span>
                     <div className="flex-1">
                        <div className="flex justify-between items-center mb-1">
                          <span className="text-sm font-medium text-slate-700">{item.domain}</span>
                          <span className="text-xs font-bold text-orange-600">{item.count}</span>
                        </div>
                        <div className="w-full bg-slate-100 rounded-full h-1.5 overflow-hidden">
                          <div 
                            className="bg-indigo-500 h-full rounded-full" 
                            style={{ width: `${(item.count / domainStatsArray[0].count) * 100}%` }}
                          />
                        </div>
                     </div>
                   </div>
                 ))}
               </div>
             ) : (
               <div className="text-center text-slate-400 py-8 text-sm">
                 No promotional or spam domains detected.
               </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};
